     1→/**
     2→ * TaskBar Component
     3→ * Draggable/resizable task bar for Gantt timeline
     4→ */
     5→
     6→import { useState, useRef, useEffect } from 'react';
     7→import type { Task, TaskPriority, BaselineTask } from '../../types';
     8→import { TASK_BAR_HEIGHT, type ZoomLevel, dateToX, xToDate, calculateBarWidth, isValidDateRange, snapToGrid } from './utils';
     9→import { calculateVarianceDays, getVarianceStatus } from '../../utils/baseline';
    10→
    11→interface TaskBarProps {
    12→  task: Task;
    13→  startDate: Date;
    14→  zoom: ZoomLevel;
    15→  rowY: number;
    16→  onUpdate: (taskId: string, updates: Partial<Task>) => void;
    17→  onClick: (task: Task) => void;
    18→  isCritical?: boolean; // Phase 1.3: Critical path indicator
    19→  baselineTask?: BaselineTask; // Phase 1.4: Baseline comparison
    20→}
    21→
    22→export function TaskBar({ task, startDate, zoom, rowY, onUpdate, onClick, isCritical = false, baselineTask }: TaskBarProps) {
    23→  const barRef = useRef<HTMLDivElement>(null);
    24→  const [isDragging, setIsDragging] = useState(false);
    25→  const [isResizing, setIsResizing] = useState(false);
    26→  const [dragStart, setDragStart] = useState({ x: 0, startDate: new Date(), dueDate: new Date() });
    27→
    28→  // Get task dates (use defaults if missing)
    29→  const taskStartDate = task.startDate ? new Date(task.startDate) : task.dueDate ? new Date(task.dueDate) : new Date();
    30→  const taskDueDate = task.dueDate ? new Date(task.dueDate) : task.startDate ? new Date(task.startDate) : new Date();
    31→
    32→  // Calculate bar position and width
    33→  const x = dateToX(taskStartDate, startDate, zoom);
    34→  const width = calculateBarWidth(taskStartDate, taskDueDate, zoom);
    35→  const y = rowY + (60 - TASK_BAR_HEIGHT) / 2; // Center in row
    36→
    37→  // Priority colors
    38→  const getPriorityColor = (priority: TaskPriority | undefined) => {
    39→    switch (priority) {
    40→      case 'high':
    41→        return 'bg-status-error text-white';
    42→      case 'medium':
    43→        return 'bg-accent-magenta dark:bg-accent-cyan text-white dark:text-dark-background';
    44→      case 'low':
    45→        return 'bg-status-info text-white';
    46→      default:
    47→        return 'bg-neutral-400 text-text-light-primary dark:text-text-dark-primary';
    48→    }
    49→  };
    50→
    51→  // Handle drag start
    52→  const handleDragStart = (e: React.MouseEvent) => {
    53→    if (isResizing) return;
    54→
    55→    e.preventDefault();
    56→    e.stopPropagation();
    57→
    58→    setIsDragging(true);
    59→    setDragStart({
    60→      x: e.clientX,
    61→      startDate: taskStartDate,
    62→      dueDate: taskDueDate,
    63→    });
    64→  };
    65→
    66→  // Handle resize start
    67→  const handleResizeStart = (e: React.MouseEvent) => {
    68→    e.preventDefault();
    69→    e.stopPropagation();
    70→
    71→    setIsResizing(true);
    72→    setDragStart({
    73→      x: e.clientX,
    74→      startDate: taskStartDate,
    75→      dueDate: taskDueDate,
    76→    });
    77→  };
    78→
    79→  // Global mouse move handler
    80→  useEffect(() => {
    81→    if (!isDragging && !isResizing) return;
    82→
    83→    const handleMouseMove = (e: MouseEvent) => {
    84→      const deltaX = e.clientX - dragStart.x;
    85→
    86→      if (isDragging) {
    87→        // Calculate new dates based on drag offset
    88→        const newStartDate = xToDate(dateToX(dragStart.startDate, startDate, zoom) + deltaX, startDate, zoom);
    89→        const newDueDate = xToDate(dateToX(dragStart.dueDate, startDate, zoom) + deltaX, startDate, zoom);
    90→
    91→        // Snap to grid
    92→        const snappedStart = snapToGrid(newStartDate);
    93→        const snappedDue = snapToGrid(newDueDate);
    94→
    95→        // Update task dates
    96→        if (isValidDateRange(snappedStart, snappedDue)) {
    97→          onUpdate(task.id, {
    98→            startDate: snappedStart.toISOString(),
    99→            dueDate: snappedDue.toISOString(),
   100→          });
   101→        }
   102→      } else if (isResizing) {
   103→        // Calculate new due date based on resize
   104→        const newDueDate = xToDate(dateToX(dragStart.dueDate, startDate, zoom) + deltaX, startDate, zoom);
   105→        const snappedDue = snapToGrid(newDueDate);
   106→
   107→        // Ensure valid range
   108→        if (isValidDateRange(dragStart.startDate, snappedDue)) {
   109→          onUpdate(task.id, {
   110→            dueDate: snappedDue.toISOString(),
   111→          });
   112→        }
   113→      }
   114→    };
   115→
   116→    const handleMouseUp = () => {
   117→      setIsDragging(false);
   118→      setIsResizing(false);
   119→    };
   120→
   121→    window.addEventListener('mousemove', handleMouseMove);
   122→    window.addEventListener('mouseup', handleMouseUp);
   123→
   124→    return () => {
   125→      window.removeEventListener('mousemove', handleMouseMove);
   126→      window.removeEventListener('mouseup', handleMouseUp);
   127→    };
   128→  }, [isDragging, isResizing, dragStart, task.id, startDate, zoom, onUpdate]);
   129→
   130→  // Phase 1.5: Progress percentage (0-100)
   131→  const progress = task.progress || 0;
   132→
   133→  // Get progress fill color (darker shade of bar color)
   134→  const getProgressFillColor = (priority: TaskPriority | undefined): string => {
   135→    if (isCritical) {
   136→      return 'rgba(220, 38, 38, 0.7)'; // Dark red for critical
   137→    }
   138→    switch (priority) {
   139→      case 'high':
   140→        return 'rgba(185, 28, 28, 0.8)'; // Darker red
   141→      case 'medium':
   142→        return 'rgba(157, 23, 77, 0.8)'; // Darker magenta
   143→      case 'low':
   144→        return 'rgba(30, 64, 175, 0.8)'; // Darker blue
   145→      default:
   146→        return 'rgba(115, 115, 115, 0.8)'; // Darker gray
   147→    }
   148→  };
   149→
   150→  // Phase 1.4: Calculate baseline variance
   151→  const varianceDays = baselineTask ? calculateVarianceDays(task, baselineTask) : null;
   152→  const varianceStatus = getVarianceStatus(varianceDays);
   153→
   154→  // Baseline bar positioning (if baseline exists)
   155→  let baselineX = 0;
   156→  let baselineWidth = 0;
   157→  if (baselineTask && (baselineTask.startDate || baselineTask.dueDate)) {
   158→    const baselineStartDate = baselineTask.startDate ? new Date(baselineTask.startDate) : baselineTask.dueDate ? new Date(baselineTask.dueDate) : new Date();
   159→    const baselineDueDate = baselineTask.dueDate ? new Date(baselineTask.dueDate) : baselineTask.startDate ? new Date(baselineTask.startDate) : new Date();
   160→    baselineX = dateToX(baselineStartDate, startDate, zoom);
   161→    baselineWidth = calculateBarWidth(baselineStartDate, baselineDueDate, zoom);
   162→  }
   163→
   164→  // Phase 1.6: Milestone rendering (diamond marker instead of bar)
   165→  if (task.isMilestone) {
   166→    const milestoneDate = task.dueDate ? new Date(task.dueDate) : new Date();
   167→    const milestoneX = dateToX(milestoneDate, startDate, zoom);
   168→    const milestoneY = rowY + (60 - 28) / 2; // Center 28px diagonal diamond
   169→
   170→    return (
   171→      <div
   172→        className="absolute cursor-pointer group"
   173→        style={{ left: milestoneX - 14, top: milestoneY }} // Center diamond on date
   174→        onClick={(e) => {
   175→          e.stopPropagation();
   176→          onClick(task);
   177→        }}
   178→      >
