  return (
    <>
      {/* Baseline bar (behind current bar) */}
      {baselineTask && (baselineTask.startDate || baselineTask.dueDate) && (
        <div
          className="absolute rounded-button border border-dashed border-neutral-400 dark:border-neutral-600 bg-neutral-200/30 dark:bg-neutral-700/30"
          style={{
            left: baselineX,
            top: y,
            width: Math.max(baselineWidth, 40),
            height: TASK_BAR_HEIGHT,
